INSERT INTO public.crm_flow_steps (key, label, message)
VALUES 
  ('comercial_saudacao_lead', 'Comercial: Saudação Lead', 'Olá! 👋 Seja bem-vindo à STH Method. Somos uma consultoria especializada em emagrecimento, hipertrofia, performance e saúde baseada em ciência. Como podemos ajudar?\n\n1️⃣ Conhecer a Consultoria\n2️⃣ Ver Planos e Valores\n3️⃣ Iniciar Minha Inscrição\n4️⃣ Formas de Pagamento\n5️⃣ Falar com Especialista'),
  ('comercial_conhecer_consultoria', 'Comercial: Opção 1 - Conhecer', 'A STH Method oferece acompanhamento individualizado para pessoas que buscam melhorar sua composição corporal, saúde e performance. O acompanhamento inclui:\n\n✅ Planejamento nutricional individualizado\n✅ Treinamento personalizado\n✅ Aplicativo ST Coach\n✅ Portal exclusivo do aluno\n✅ Atualizações periódicas\n✅ Estratégias baseadas em evidências científicas\n✅ Acompanhamento contínuo\n\nDeseja conhecer nossos planos?\n\n1️⃣ Sim\n2️⃣ Falar com Especialista'),
  ('comercial_ident_ativo', 'Comercial: Identificação Aluno Ativo', 'Olá, {nome}!\n\nIdentificamos que você possui uma consultoria ativa na STH Method.\n\nPara assuntos relacionados ao seu acompanhamento, atualizações, pagamentos, renovação ou suporte administrativo, você será direcionado ao setor responsável.\n\n🏆 Sucesso do Aluno | STH Method\n\nTransferindo atendimento...'),
  ('comercial_ident_inativo', 'Comercial: Identificação Aluno Inativo', 'Olá, {nome}!\n\nLocalizamos seu cadastro em nossa base.\n\nPara reativação ou continuidade do acompanhamento, você será direcionado ao setor responsável.\n\n🏆 Sucesso do Aluno | STH Method\n\nTransferindo atendimento...'),
  ('comercial_ident_exaluno', 'Comercial: Identificação Ex-Aluno', 'Olá, {nome}!\n\nEncontramos seu histórico na STH Method.\n\nPara retorno à consultoria ou novas condições de acompanhamento, você será direcionado ao setor responsável.\n\n🏆 Sucesso do Aluno | STH Method\n\nTransferindo atendimento...')
